1409: SECStatus zlibCertificateDecode(const SECItem* input, unsigned char* output,
1410:                                 size_t outputLen, size_t* usedLen) {
1411:   SECStatus rv = SECFailure;
1412:   if (!input || !input->data || input->len == 0 || !output || outputLen == 0) {
1413:     PR_SetError(SEC_ERROR_INVALID_ARGS, 0);
1414:     return rv;
1415:   }
1416: 
1417:   z_stream strm = {};
1418: 
1419:   if (inflateInit(&strm) != Z_OK) {
1420:     PR_SetError(SEC_ERROR_LIBRARY_FAILURE, 0);
1421:     return rv;
1422:   }
1423: 
1424:   auto cleanup = MakeScopeExit([&] {
1425:     GatherCertificateCompressionTelemetry(rv, zlib, *usedLen, input->len);
1426:     (void)inflateEnd(&strm);
1427:   });
1428: 
1429:   strm.avail_in = input->len;
1430:   strm.next_in = input->data;
1431: 
1432:   strm.avail_out = outputLen;
1433:   strm.next_out = output;
1434: 
1435:   int ret = inflate(&strm, Z_FINISH);
1436:   bool ok = ret == Z_STREAM_END && strm.avail_in == 0 && strm.avail_out == 0;
1437:   if (!ok) {
1438:     PR_SetError(SEC_ERROR_BAD_DATA, 0);
1439:     return rv;
1440:   }
1441: 
1442:   *usedLen = strm.total_out;
1443:   rv = SECSuccess;
1444:   return rv;
1445: }
