1447: SECStatus brotliCertificateDecode(const SECItem* input, unsigned char* output,
1448:                                   size_t outputLen, size_t* usedLen) {
1449:   SECStatus rv = SECFailure;
1450: 
1451:   if (!input || !input->data || input->len == 0 || !output || outputLen == 0) {
1452:     PR_SetError(SEC_ERROR_INVALID_ARGS, 0);
1453:     return rv;
1454:   }
1455: 
1456:   auto cleanup = MakeScopeExit([&] {
1457:     GatherCertificateCompressionTelemetry(rv, brotli, *usedLen, input->len);
1458:   });
1459: 
1460:   size_t uncompressedSize = outputLen;
1461:   BrotliDecoderResult result = BrotliDecoderDecompress(
1462:       input->len, input->data, &uncompressedSize, output);
1463: 
1464:   if (result != BROTLI_DECODER_RESULT_SUCCESS) {
1465:     PR_SetError(SEC_ERROR_BAD_DATA, 0);
1466:     return rv;
1467:   }
1468: 
1469:   *usedLen = uncompressedSize;
1470:   rv = SECSuccess;
1471:   return rv;
1472: }
