1499: static nsresult nsSSLIOLayerSetOptions(PRFileDesc* fd, bool forSTARTTLS,
1500:                                        bool haveProxy, const char* host,
1501:                                        int32_t port,
1502:                                        NSSSocketControl* infoObject) {
1503:   if (forSTARTTLS || haveProxy) {
1504:     if (SECSuccess != SSL_OptionSet(fd, SSL_SECURITY, false)) {
1505:       return NS_ERROR_FAILURE;
1506:     }
1507:   }
1508: 
1509:   SSLVersionRange range;
1510:   if (SSL_VersionRangeGet(fd, &range) != SECSuccess) {
1511:     return NS_ERROR_FAILURE;
1512:   }
1513: 
1514:   // Set TLS 1.3 compat mode.
1515:   if (SECSuccess != SSL_OptionSet(fd, SSL_ENABLE_TLS13_COMPAT_MODE, PR_TRUE)) {
1516:     MOZ_LOG(gPIPNSSLog, LogLevel::Error,
1517:             ("[%p] nsSSLIOLayerSetOptions: Setting compat mode failed\n", fd));
1518:   }
1519: 
1520:   // setting TLS max version
1521:   uint32_t versionFlags =
1522:       getTLSProviderFlagMaxVersion(infoObject->GetProviderTlsFlags());
1523:   if (versionFlags) {
